import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.1N8rnUr9.js";const b=JSON.parse('{"title":"Hooks & Filters","description":"","frontmatter":{},"headers":[],"relativePath":"developer/hooks.md","filePath":"developer/hooks.md","lastUpdated":1775715475000}'),s={name:"developer/hooks.md"};function r(l,e,n,d,h,c){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="hooks-filters" tabindex="-1">Hooks &amp; Filters <a class="header-anchor" href="#hooks-filters" aria-label="Permalink to &quot;Hooks &amp; Filters&quot;">​</a></h1><p>TubeBay provides a set of WordPress action hooks and filters, enabling developers to extend, customize, and integrate with the plugin without modifying its core source files.</p><div class="info custom-block"><p class="custom-block-title">Since v1.0.0</p><p>All hooks listed on this page were introduced in TubeBay <strong>1.0.0</strong>.</p></div><h2 id="hook-naming-convention" tabindex="-1">Hook Naming Convention <a class="header-anchor" href="#hook-naming-convention" aria-label="Permalink to &quot;Hook Naming Convention&quot;">​</a></h2><p>All hooks are prefixed with <code>tubebay_</code> to avoid collisions:</p><ul><li><strong>Actions</strong> — Use <code>do_action( &#39;tubebay_*&#39; )</code></li><li><strong>Filters</strong> — Use <code>apply_filters( &#39;tubebay_*&#39; )</code></li></ul><hr><h2 id="core-hooks" tabindex="-1">Core Hooks <a class="header-anchor" href="#core-hooks" aria-label="Permalink to &quot;Core Hooks&quot;">​</a></h2><h3 id="tubebay-loaded" tabindex="-1"><code>tubebay_loaded</code> <a class="header-anchor" href="#tubebay-loaded" aria-label="Permalink to &quot;`tubebay_loaded`&quot;">​</a></h3><p>Fires after all plugin components are initialized.</p><ul><li><strong>Type:</strong> Action</li><li><strong>File:</strong> <code>app/Core/Plugin.php</code></li></ul><h3 id="tubebay-before-sync" tabindex="-1"><code>tubebay_before_sync</code> <a class="header-anchor" href="#tubebay-before-sync" aria-label="Permalink to &quot;`tubebay_before_sync`&quot;">​</a></h3><p>Fires before the YouTube library sync process starts.</p><ul><li><strong>Type:</strong> Action</li><li><strong>File:</strong> <code>app/Data/Repositories/SyncRepository.php</code></li></ul><h3 id="tubebay-after-sync" tabindex="-1"><code>tubebay_after_sync</code> <a class="header-anchor" href="#tubebay-after-sync" aria-label="Permalink to &quot;`tubebay_after_sync`&quot;">​</a></h3><p>Fires after the YouTube library sync process completes.</p><ul><li><strong>Type:</strong> Action</li><li><strong>Parameters:</strong> <code>$synced_count</code> (int), <code>$errors</code> (array)</li></ul><hr><h2 id="data-filters" tabindex="-1">Data Filters <a class="header-anchor" href="#data-filters" aria-label="Permalink to &quot;Data Filters&quot;">​</a></h2><h3 id="tubebay-channel-data" tabindex="-1"><code>tubebay_channel_data</code> <a class="header-anchor" href="#tubebay-channel-data" aria-label="Permalink to &quot;`tubebay_channel_data`&quot;">​</a></h3><p>Filters the channel metadata (Title, Description) before it is saved or displayed.</p><ul><li><strong>Type:</strong> Filter</li><li><strong>Parameters:</strong> <code>$data</code> (array)</li></ul><h3 id="tubebay-video-data" tabindex="-1"><code>tubebay_video_data</code> <a class="header-anchor" href="#tubebay-video-data" aria-label="Permalink to &quot;`tubebay_video_data`&quot;">​</a></h3><p>Filters individual video data before it is cached.</p><ul><li><strong>Type:</strong> Filter</li><li><strong>Parameters:</strong> <code>$video_data</code> (array), <code>$video_id</code> (string)</li></ul><hr><h2 id="frontend-player-hooks" tabindex="-1">Frontend Player Hooks <a class="header-anchor" href="#frontend-player-hooks" aria-label="Permalink to &quot;Frontend Player Hooks&quot;">​</a></h2><h3 id="tubebay-player-args" tabindex="-1"><code>tubebay_player_args</code> <a class="header-anchor" href="#tubebay-player-args" aria-label="Permalink to &quot;`tubebay_player_args`&quot;">​</a></h3><p>Filters the arguments passed to the YouTube IFrame API (e.g., <code>autoplay</code>, <code>controls</code>).</p><ul><li><strong>Type:</strong> Filter</li><li><strong>Parameters:</strong> <code>$args</code> (array), <code>$product_id</code> (int)</li></ul><h3 id="tubebay-player-html" tabindex="-1"><code>tubebay_player_html</code> <a class="header-anchor" href="#tubebay-player-html" aria-label="Permalink to &quot;`tubebay_player_html`&quot;">​</a></h3><p>Filters the final HTML output of the video player.</p><ul><li><strong>Type:</strong> Filter</li><li><strong>Parameters:</strong> <code>$html</code> (string), <code>$video_id</code> (string), <code>$product_id</code> (int)</li></ul><h3 id="tubebay-before-player-tubebay-after-player" tabindex="-1"><code>tubebay_before_player</code> / <code>tubebay_after_player</code> <a class="header-anchor" href="#tubebay-before-player-tubebay-after-player" aria-label="Permalink to &quot;`tubebay_before_player` / `tubebay_after_player`&quot;">​</a></h3><p>Actions to inject HTML before or after the player wrapper.</p><ul><li><strong>Type:</strong> Action</li><li><strong>Parameters:</strong> <code>$product_id</code> (int)</li></ul><hr><h2 id="admin-hooks" tabindex="-1">Admin Hooks <a class="header-anchor" href="#admin-hooks" aria-label="Permalink to &quot;Admin Hooks&quot;">​</a></h2><h3 id="tubebay-admin-script-data" tabindex="-1"><code>tubebay_admin_script_data</code> <a class="header-anchor" href="#tubebay-admin-script-data" aria-label="Permalink to &quot;`tubebay_admin_script_data`&quot;">​</a></h3><p>Filters the data passed to the React admin app.</p><ul><li><strong>Type:</strong> Filter</li><li><strong>Parameters:</strong> <code>$data</code> (array)</li></ul><div class="language-php vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">add_filter</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;tubebay_admin_script_data&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">function</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">( $data ) {</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    $data[</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;custom_config&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;value&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    return</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> $data;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} );</span></span></code></pre></div><h3 id="tubebay-enqueue-admin-assets" tabindex="-1"><code>tubebay_enqueue_admin_assets</code> <a class="header-anchor" href="#tubebay-enqueue-admin-assets" aria-label="Permalink to &quot;`tubebay_enqueue_admin_assets`&quot;">​</a></h3><p>Action to enqueue additional scripts or styles on TubeBay admin pages.</p><ul><li><strong>Type:</strong> Action</li></ul>',45)])])}const u=a(s,[["render",r]]);export{b as __pageData,u as default};
